        de: 'kein Datum',
        en: 'no date',
        pl: 'brak daty',
      });

  return (
    <KangurMobileInsetPanel gap={10}>
      <View
        style={{
          flexDirection: 'row',
          justifyContent: 'space-between',
          alignItems: 'flex-start',
          gap: 12,
